; field_moves.asm — field-move static data + predicate.
;
; Holds the shared FieldMoveDisplayData / FieldMoveNames tables (generated by
; tools/gen_field_moves.py from data/moves/{field_moves,field_move_names}.asm)
; and the linear-scan predicate the overworld party menu uses to label a mon's
; field moves. Faithful to pret engine/menus/text_box.asm:GetMonFieldMoves — the
; same data-driven scan (one table, $FF-terminated) instead of a baked cmp-chain.
;
; This data must live in a LINKED source (party_menu.asm calls IsFieldMove), so
; it is its own GAME_SRCS module rather than riding battle_data.asm (BATTLE_SRCS,
; not yet linked). Embedded data goes in .data per the linker rule in
; docs/assembly.md (.rodata has no output-section rule → reads back as zero).
;
; Build: nasm -f coff -I include/ -I . -o field_moves.o field_moves.asm
; ---------------------------------------------------------------------------
bits 32

%include "gb_constants.inc"

global FieldMoveDisplayData
global FieldMoveNames
global IsFieldMove

section .data
align 4
%include "assets/field_moves.inc"

section .text

; ---------------------------------------------------------------------------
; IsFieldMove — is move id AL a field move, and if so where is its name?
; In:  AL = move id.
; Out: CF=1 + EAX = flat pointer to the move's '@'-terminated name in
;          FieldMoveNames (suitable for place_flat_str), if AL is a field move;
;      CF=0 + EAX = 0 otherwise.
; Preserves EBX/ECX/EDX/ESI/EDI/EBP (party_menu's .bp_loop keeps ESI/EDX/ECX live
; across the call). Faithful to GetMonFieldMoves' .fieldMoveLoop scan: walk the
; $FF-terminated FieldMoveDisplayData, on a match take the 1-based name index and
; skip that many '@'-terminated strings into FieldMoveNames.
; ---------------------------------------------------------------------------
IsFieldMove:
    push ebx
    push edx
    push esi
    movzx ebx, al                   ; EBX = target move id
    mov esi, FieldMoveDisplayData
.scan:
    movzx eax, byte [esi]           ; record's move id
    cmp eax, 0xFF                   ; $FF terminator → not a field move
    je .not_found
    cmp eax, ebx
    je .found
    add esi, 3                      ; next 3-byte record
    jmp .scan
.found:
    movzx eax, byte [esi + 1]       ; 1-based FieldMoveNames index
    mov esi, FieldMoveNames
    dec eax                         ; strings to skip before the target
.skip_names:
    test eax, eax
    jz .at_name
.skip_one:
    mov dl, [esi]
    inc esi
    cmp dl, 0x50                    ; '@' terminator
    jne .skip_one
    dec eax
    jmp .skip_names
.at_name:
    mov eax, esi                    ; EAX = flat pointer to the name
    pop esi
    pop edx
    pop ebx
    stc
    ret
.not_found:
    xor eax, eax
    pop esi
    pop edx
    pop ebx
    clc
    ret
